### C Implementation of `remove_duplicates`

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the maximum possible number of unique integers
#define MAX_UNIQUE 100000

// Function to remove duplicates based on a threshold
int* remove_duplicates(int* numbers, int length, int threshold, int* result_length) {
    // Use an array to count occurrences of each number
    int count[MAX_UNIQUE] = {0};
    int* result = (int*)malloc(length * sizeof(int));
    int index = 0;

    // First pass: count occurrences of each number
    for (int i = 0; i < length; i++) {
        int num = numbers[i];
        // Ensure the number is within the range of our count array
        if (num >= 0 && num < MAX_UNIQUE) {
            count[num]++;
        }
    }

    // Second pass: build the result list
    for (int i = 0; i < length; i++) {
        int num = numbers[i];
        if (num >= 0 && num < MAX_UNIQUE && count[num] <= threshold) {
            result[index++] = num;
            count[num] = threshold + 1; // Mark as processed
        }
    }

    // Set the result length and return
    *result_length = index;
    return result;
}

// Example usage
